1	/**
2	 * Transport state machine with cursor tracking.
3	 * Writes cursor position, state, and BPM to SharedArrayBuffer
4	 * for lock-free audio-thread <-> UI-thread communication.
5	 */
6	
7	import { createTempoMap, type TempoMap } from "./tempo-map";
8	import { TransportLayout } from "./shared-buffer-layout";
9	
10	export type TransportState = "stopped" | "playing" | "paused";
11	
12	const STATE_STOPPED = 0;
13	const STATE_PLAYING = 1;
14	const STATE_PAUSED = 2;
15	
16	export type LoopRegion = {
17	  readonly enabled: boolean;
18	  readonly start: number;
19	  readonly end: number;
20	};
21	
22	export type TransportClock = {
23	  readonly state: TransportState;
24	  play(): void;
25	  pause(): void;
26	  stop(): void;
27	  seek(seconds: number): void;
28	  setBpm(bpm: number): void;
29	  setLoop(region: LoopRegion): void;
30	  getLoop(): LoopRegion;
31	  /** Pure read — computes current cursor position without side effects. */
32	  getCursorSeconds(): number;
33	  /** Advances playback state: handles loop wrap, writes SAB. Call from scheduler. */
34	  updateCursor(): number;
35	  /** Returns true if the last updateCursor() call triggered a loop wrap. */
36	  didLoopWrap(): boolean;
37	  getTempoMap(): TempoMap;
38	  dispose(): void;
39	};
40	
41	export function createTransportClock(
42	  ctx: AudioContext,
43	  transportSAB: SharedArrayBuffer,
44	  initialBpm = 120,
45	  sampleRate?: number,
46	): TransportClock {
47	  const rate = sampleRate ?? ctx.sampleRate;
48	
49	  // SAB views -- created once (zero-allocation convention INV-3)
50	  const cursorView = new Float64Array(
51	    transportSAB,
52	    TransportLayout.CURSOR_SECONDS,
53	    1,
54	  );
55	  const stateView = new Uint8Array(transportSAB, TransportLayout.STATE, 1);
56	  const bpmView = new Float32Array(transportSAB, TransportLayout.BPM, 1);
57	
58	  let currentState: TransportState = "stopped";
59	  let cursorSeconds = 0;
60	  let playStartContextTime = 0;
61	  let playStartCursorSeconds = 0;
62	  let tempoMap = createTempoMap(
63	    initialBpm,
64	    { numerator: 4, denominator: 4 },
65	    rate,
66	  );
67	  let loop: LoopRegion = { enabled: false, start: 0, end: 0 };
68	  let loopWrapped = false;
69	
70	  // Write initial values to SAB
71	  stateView[0] = STATE_STOPPED;
72	  bpmView[0] = initialBpm;
73	  cursorView[0] = 0;
74	
75	  function writeSABState(state: number): void {
76	    stateView[0] = state;
77	  }
78	
79	  function writeSABCursor(seconds: number): void {
80	    cursorView[0] = seconds;
81	  }
82	
83	  const clock: TransportClock = {
84	    get state(): TransportState {
85	      return currentState;
86	    },
87	
88	    play(): void {
89	      if (currentState === "playing") return;
90	
91	      playStartContextTime = ctx.currentTime;
92	      playStartCursorSeconds = cursorSeconds;
93	      currentState = "playing";
94	      writeSABState(STATE_PLAYING);
95	    },
96	
97	    pause(): void {
98	      if (currentState !== "playing") return;
99	
100	      cursorSeconds =
101	        playStartCursorSeconds + (ctx.currentTime - playStartContextTime);
102	      currentState = "paused";
103	      writeSABState(STATE_PAUSED);
104	      writeSABCursor(cursorSeconds);
105	    },
106	
107	    stop(): void {
108	      if (currentState === "stopped") return;
109	
110	      cursorSeconds = 0;
111	      currentState = "stopped";
112	      writeSABState(STATE_STOPPED);
113	      writeSABCursor(0);
114	    },
115	
116	    seek(seconds: number): void {
117	      const clamped = Math.max(0, seconds);
118	      cursorSeconds = clamped;
119	      if (currentState === "playing") {
120	        playStartContextTime = ctx.currentTime;
121	        playStartCursorSeconds = clamped;
122	      }
123	      writeSABCursor(clamped);
124	    },
125	
126	    setBpm(bpm: number): void {
127	      const clamped = Math.min(999, Math.max(20, bpm));
128	      tempoMap = createTempoMap(clamped, tempoMap.timeSignature, rate);
129	      bpmView[0] = clamped;
130	    },
131	
132	    setLoop(region: LoopRegion): void {
133	      loop = region;
134	    },
135	
136	    getLoop(): LoopRegion {
137	      return loop;
138	    },
139	
140	    getCursorSeconds(): number {
141	      if (currentState === "playing") {
142	        const elapsed = ctx.currentTime - playStartContextTime;
143	        let pos = playStartCursorSeconds + elapsed;
144	
145	        // Apply loop wrap (pure computation, no mutation)
146	        if (loop.enabled && loop.end > loop.start && pos >= loop.end) {
147	          const loopLen = loop.end - loop.start;
148	          pos = loop.start + ((pos - loop.start) % loopLen);
149	        }
150	
151	        return pos;
152	      }
153	      return cursorSeconds;
154	    },
155	
156	    updateCursor(): number {
157	      loopWrapped = false;
158	      if (currentState === "playing") {
159	        const elapsed = ctx.currentTime - playStartContextTime;
160	        let pos = playStartCursorSeconds + elapsed;
161	
162	        if (loop.enabled && loop.end > loop.start && pos >= loop.end) {
163	          const loopLen = loop.end - loop.start;
164	          pos = loop.start + ((pos - loop.start) % loopLen);
165	          playStartContextTime = ctx.currentTime;
166	          playStartCursorSeconds = pos;
167	          loopWrapped = true;
168	        }
169	
170	        cursorSeconds = pos;
171	        writeSABCursor(pos);
172	        return pos;
173	      }
174	      return cursorSeconds;
175	    },
176	
177	    didLoopWrap(): boolean {
178	      return loopWrapped;
179	    },
180	
181	    getTempoMap(): TempoMap {
182	      return tempoMap;
183	    },
184	
185	    dispose(): void {
186	      currentState = "stopped";
187	      writeSABState(STATE_STOPPED);
188	    },
189	  };
190	
191	  return clock;
192	}
