1	/**
2	 * AudioContext lifecycle management.
3	 * Handles creation, suspension, resumption on user gesture,
4	 * and AudioWorklet module loading.
5	 */
6	
7	export class AudioEngineError extends Error {
8	  constructor(message: string, cause: unknown) {
9	    super(message, { cause });
10	    this.name = "AudioEngineError";
11	  }
12	}
13	
14	export type AudioEngineState =
15	  | "uninitialized"
16	  | "suspended"
17	  | "running"
18	  | "closed";
19	
20	export type AudioEngineContext = {
21	  readonly ctx: AudioContext;
22	  readonly state: AudioEngineState;
23	  resume: () => Promise<void>;
24	  close: () => Promise<void>;
25	  loadWorkletModule: (url: string) => Promise<void>;
26	};
27	
28	/**
29	 * Creates an AudioContext in suspended state.
30	 * Call resume() after a user gesture to start audio.
31	 */
32	export function createAudioEngine(): AudioEngineContext {
33	  const ctx = new AudioContext();
34	
35	  const engine: AudioEngineContext = {
36	    ctx,
37	    get state(): AudioEngineState {
38	      switch (ctx.state) {
39	        case "suspended":
40	          return "suspended";
41	        case "running":
42	          return "running";
43	        case "closed":
44	          return "closed";
45	        default:
46	          return "uninitialized";
47	      }
48	    },
49	    async resume(): Promise<void> {
50	      if (ctx.state === "suspended") {
51	        try {
52	          await ctx.resume();
53	        } catch (err) {
54	          throw new AudioEngineError(
55	            "Audio playback was blocked by the browser. Click the page and try again.",
56	            err,
57	          );
58	        }
59	      }
60	    },
61	    async close(): Promise<void> {
62	      if (ctx.state !== "closed") {
63	        await ctx.close();
64	      }
65	    },
66	    async loadWorkletModule(url: string): Promise<void> {
67	      try {
68	        await ctx.audioWorklet.addModule(url);
69	      } catch (err) {
70	        throw new AudioEngineError(
71	          `Failed to load audio worklet module "${url}". Check your network connection and reload.`,
72	          err,
73	        );
74	      }
75	    },
76	  };
77	
78	  return engine;
79	}
