1	/**
2	 * Base effect builder with wet/dry bypass infrastructure.
3	 * Every effect uses this to get consistent bypass, mix, and param management.
4	 */
5	
6	import type { EffectInstance, EffectParameterSchema } from "./types";
7	
8	function clamp(v: number, min: number, max: number): number {
9	  return Math.min(max, Math.max(min, v));
10	}
11	
12	export type ApplyParamFn = (
13	  key: string,
14	  value: number,
15	  setMix: (wet: number) => void,
16	) => void;
17	
18	export type CreateEffectOptions = {
19	  ctx: AudioContext;
20	  id: string;
21	  typeId: string;
22	  params: readonly EffectParameterSchema[];
23	  /** Wire internal effect nodes between inputNode and outputNode */
24	  buildChain(inputNode: GainNode, outputNode: GainNode): void;
25	  /** Called when a parameter changes. Use setMix callback for mix params. */
26	  applyParam: ApplyParamFn;
27	  /** Resolve a param key to its underlying AudioParam for automation */
28	  resolveAudioParam?: (key: string) => AudioParam | undefined;
29	  /** Clean up internal effect nodes (stop oscillators, disconnect nodes) */
30	  disposeChain?: () => void;
31	};
32	
33	/**
34	 * Creates a base effect instance with:
35	 * - Wet/dry split: input -> dryGain -> output, input -> [effect chain] -> wetGain -> output
36	 * - Bypass toggle (sets dry=1, wet=0)
37	 * - Parameter storage with clamping
38	 */
39	export function createBaseEffect(opts: CreateEffectOptions): EffectInstance {
40	  const { ctx, id, typeId, params, applyParam } = opts;
41	
42	  const input = ctx.createGain();
43	  const output = ctx.createGain();
44	  const dryGain = ctx.createGain();
45	  const wetGain = ctx.createGain();
46	
47	  // Internal nodes for the effect chain
48	  const effectInput = ctx.createGain();
49	  const effectOutput = ctx.createGain();
50	
51	  // Dry path: input -> dryGain -> output
52	  input.connect(dryGain);
53	  dryGain.connect(output);
54	
55	  // Wet path: input -> effectInput -> [effect chain] -> effectOutput -> wetGain -> output
56	  input.connect(effectInput);
57	  opts.buildChain(effectInput, effectOutput);
58	  effectOutput.connect(wetGain);
59	  wetGain.connect(output);
60	
61	  // Default: fully wet (no dry signal)
62	  dryGain.gain.value = 0;
63	  wetGain.gain.value = 1;
64	
65	  // Parameter storage
66	  const paramMap = new Map<
67	    string,
68	    { schema: EffectParameterSchema; value: number }
69	  >();
70	  for (const p of params) {
71	    paramMap.set(p.key, { schema: p, value: p.default });
72	  }
73	
74	  let bypassed = false;
75	  let mixLevel = 1; // 0 = fully dry, 1 = fully wet
76	
77	  // 5ms ramp avoids audible clicks on gain changes
78	  const RAMP_TIME = 0.005;
79	
80	  function rampTo(param: AudioParam, value: number): void {
81	    if (typeof param.linearRampToValueAtTime === "function") {
82	      param.setValueAtTime(param.value, ctx.currentTime);
83	      param.linearRampToValueAtTime(value, ctx.currentTime + RAMP_TIME);
84	    } else {
85	      param.value = value;
86	    }
87	  }
88	
89	  function applyMix(): void {
90	    if (bypassed) {
91	      rampTo(dryGain.gain, 1);
92	      rampTo(wetGain.gain, 0);
93	    } else {
94	      rampTo(dryGain.gain, 1 - mixLevel);
95	      rampTo(wetGain.gain, mixLevel);
96	    }
97	  }
98	
99	  function setMix(wet: number): void {
100	    mixLevel = clamp(wet, 0, 1);
101	    applyMix();
102	  }
103	
104	  const instance: EffectInstance = {
105	    id,
106	    typeId,
107	    input,
108	    output,
109	    dryGain,
110	    wetGain,
111	    bypassed: false,
112	
113	    getParam(key: string): number {
114	      return paramMap.get(key)?.value ?? 0;
115	    },
116	
117	    setParam(key: string, value: number): void {
118	      const entry = paramMap.get(key);
119	      if (!entry) return;
120	      entry.value = clamp(value, entry.schema.min, entry.schema.max);
121	      applyParam(key, entry.value, setMix);
122	    },
123	
124	    setBypassed(b: boolean): void {
125	      bypassed = b;
126	      instance.bypassed = b;
127	      applyMix();
128	    },
129	
130	    setMix,
131	
132	    getAudioParam(key: string): AudioParam | undefined {
133	      return opts.resolveAudioParam?.(key);
134	    },
135	
136	    getParamRange(key: string): { min: number; max: number } | undefined {
137	      const entry = paramMap.get(key);
138	      if (!entry) return undefined;
139	      return { min: entry.schema.min, max: entry.schema.max };
140	    },
141	
142	    dispose(): void {
143	      opts.disposeChain?.();
144	      input.disconnect();
145	      output.disconnect();
146	      dryGain.disconnect();
147	      wetGain.disconnect();
148	      effectInput.disconnect();
149	      effectOutput.disconnect();
150	    },
151	  };
152	
153	  // Initialize all params (deferred to after instance creation)
154	  for (const [key, entry] of paramMap) {
155	    applyParam(key, entry.value, setMix);
156	  }
157	
158	  return instance;
159	}
