    const crossfadeSamples = Math.floor(STEAL_CROSSFADE_S * SR);
    let anyCompleted = false;
    for (let i = 0; i < crossfadeSamples + 10; i++) {
      const completed = alloc.processStealFade(SR);
      if (completed.count > 0) anyCompleted = true;
    }

