            voice.stealFadeGain = 0;
            voice.stealFadeSamples = 0;
            voice.pendingNote = -1;
            voice.pendingVelocity = 0;
            completedSteals[completedCount++] = i;
          }
        }
      }

      stealResult.count = completedCount;
      return stealResult;
    },

    markIdle(index: number): void {
      if (index >= 0 && index < MAX_VOICES) {
        const voice = v(voices, index);
        voice.state = "idle";
        voice.note = -1;
        voice.velocity = 0;
        voice.stealFadeSamples = 0;
        voice.stealFadeGain = 0;
        voice.pendingNote = -1;
        voice.pendingVelocity = 0;
      }
    },

    reset(): void {
      ageCounter = 0;
      for (let i = 0; i < MAX_VOICES; i++) {
        const voice = v(voices, i);
        voice.state = "idle";
        voice.note = -1;
        voice.velocity = 0;
        voice.age = 0;
        voice.stealFadeSamples = 0;
        voice.stealFadeGain = 0;
        voice.pendingNote = -1;
        voice.pendingVelocity = 0;
      }
    },
  };

  return allocator;
}

